        const response = await fetch('/api/assessments/results', {
          headers: { 'Authorization': `Bearer ${localStorage.getItem('token')}` }
        });

        if (!response.ok) throw new Error('Failed to load results');

        const data = await response.json();
        const list = document.getElementById('results-list');

        if (data.results.length === 0) {
          list.innerHTML = `
            <div class="empty-state">
              <div class="empty-state-icon">📊</div>
              <p>No completed assessments yet</p>
            </div>
          `;
          return;
        }

        list.innerHTML = data.results.map(result => {
          const date = new Date(result.completed_at);
          const hasWarnings = result.tab_switches > 0 || result.copy_paste_attempts > 0;

          return `
            <div class="result-item">
              <div class="result-score">${result.score}</div>
              <div class="result-info">
                <div class="result-title">${result.skill_name}</div>
                <div class="result-meta">
