                  ${hasWarnings ? '<span class="badge warning">⚠️ Behavioral flags</span>' : '<span class="badge">✓ Clean attempt</span>'}
                </div>
              </div>
              <a href="/assessment-results.html?id=${result.id}" class="btn btn-ghost">View Details</a>
            </div>
          `;
        }).join('');
      } catch (error) {
        console.error('Error loading results:', error);
      }
