      <div class="feedback-text" id="feedback-text"></div>
      <button class="btn btn-primary" onclick="nextQuestion()">Continue</button>
    </div>
  </div>

  <script src="/js/auth.js"></script>
  <script>
    let sessionId = null;
    let currentQuestion = null;
    let selectedAnswer = null;
    let questionStartTime = Date.now();
    let timerInterval = null;
    let timeRemaining = 120; // seconds

    // Anti-cheat tracking
    let isTabActive = true;
    let tabSwitchCount = 0;
    let copyPasteCount = 0;

    // Initialize assessment
    async function initAssessment() {
      await checkAuth();

      const skillId = localStorage.getItem('assessment_skill_id');
      if (!skillId) {
        alert('No assessment selected');
        window.location.href = '/skill-assessments.html';
        return;
      }

      try {
        const response = await fetch('/api/assessments/start', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          },
          body: JSON.stringify({ skillId: parseInt(skillId) })
        });

        if (!response.ok) throw new Error('Failed to start assessment');

        const data = await response.json();
        sessionId = data.sessionId;
        currentQuestion = data.question;

        displayQuestion();
        startTimer(currentQuestion.timeLimit);
      } catch (error) {
        console.error('Error starting assessment:', error);
        alert('Failed to start assessment');
        window.location.href = '/skill-assessments.html';
      }
    }

    // Display current question
    function displayQuestion() {
      document.getElementById('question-num').textContent = currentQuestion.questionNumber;
      document.getElementById('total-questions').textContent = currentQuestion.totalQuestions;
      document.getElementById('question-text').textContent = currentQuestion.text;

      // Update progress bar
      const progress = (currentQuestion.questionNumber / currentQuestion.totalQuestions) * 100;
      document.getElementById('progress-fill').style.width = `${progress}%`;

      // Render answer area based on question type
      const answerArea = document.getElementById('answer-area');

      if (currentQuestion.type === 'multiple_choice') {
        answerArea.innerHTML = `
          <div class="options-grid">
            ${currentQuestion.options.map((option, index) => `
              <button class="option-button" data-value="${option}" onclick="selectOption(this)">
                ${option}
              </button>
            `).join('')}
          </div>
        `;
      } else if (currentQuestion.type === 'short_answer') {
        answerArea.innerHTML = `
          <textarea class="textarea-answer" id="short-answer" placeholder="Type your answer here..."
                    onpaste="logCopyPaste(event)"></textarea>
        `;
      }

      // Reset state
      selectedAnswer = null;
      questionStartTime = Date.now();
    }

    // Select multiple choice option
    function selectOption(button) {
      document.querySelectorAll('.option-button').forEach(btn => {
        btn.classList.remove('selected');
      });
      button.classList.add('selected');
      selectedAnswer = button.dataset.value;
    }

    // Submit answer
    async function submitAnswer() {
      // Get answer
      if (currentQuestion.type === 'multiple_choice') {
        if (!selectedAnswer) {
          alert('Please select an answer');
          return;
        }
      } else {
        const textarea = document.getElementById('short-answer');
        selectedAnswer = textarea.value.trim();
        if (!selectedAnswer) {
          alert('Please provide an answer');
          return;
        }
      }

      // Calculate time taken
      const timeTaken = Math.floor((Date.now() - questionStartTime) / 1000);

      // Stop timer
      clearInterval(timerInterval);

      // Submit to API
      try {
        const response = await fetch('/api/assessments/answer', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          },
          body: JSON.stringify({
            sessionId,
            questionId: currentQuestion.id,
            answer: selectedAnswer,
            timeTaken
          })
        });

        if (!response.ok) throw new Error('Failed to submit answer');

        const data = await response.json();

        // Show feedback
        showFeedback(data);

        // Store next question if not completed
        if (!data.completed) {
          currentQuestion = data.nextQuestion;
        } else {
          // Assessment completed
          setTimeout(() => {
            window.location.href = `/assessment-results.html?session=${sessionId}`;
          }, 3000);
        }
      } catch (error) {
        console.error('Error submitting answer:', error);
        alert('Failed to submit answer');
      }
    }

    // Show feedback modal
    function showFeedback(data) {
      const modal = document.getElementById('feedback-modal');
      const icon = document.getElementById('feedback-icon');
      const title = document.getElementById('feedback-title');
      const text = document.getElementById('feedback-text');

      const isCorrect = data.feedback === 'Correct!';
      icon.textContent = isCorrect ? '✅' : '❌';
      title.textContent = data.feedback;

      let feedbackHTML = data.explanation ? `<p>${data.explanation}</p>` : '';
      if (data.aiFeedback) {
        feedbackHTML += `<p style="margin-top: 12px; padding-top: 12px; border-top: 1px solid var(--border-color);">${data.aiFeedback}</p>`;
      }
      text.innerHTML = feedbackHTML;

      modal.classList.add('show');
    }

    // Next question
    function nextQuestion() {
      document.getElementById('feedback-modal').classList.remove('show');
      displayQuestion();
      timeRemaining = currentQuestion.timeLimit;
      startTimer(currentQuestion.timeLimit);
    }

    // Timer
    function startTimer(seconds) {
      timeRemaining = seconds;
      updateTimerDisplay();

      timerInterval = setInterval(() => {
        timeRemaining--;
        updateTimerDisplay();

        if (timeRemaining <= 0) {
          clearInterval(timerInterval);
          // Auto-submit empty answer
          submitAnswer();
        }
      }, 1000);
    }

    function updateTimerDisplay() {
      const minutes = Math.floor(timeRemaining / 60);
      const seconds = timeRemaining % 60;
      const display = `${minutes}:${seconds.toString().padStart(2, '0')}`;

      const timerEl = document.getElementById('timer');
      timerEl.textContent = display;

      timerEl.className = 'timer';
      if (timeRemaining <= 10) {
        timerEl.classList.add('danger');
      } else if (timeRemaining <= 30) {
        timerEl.classList.add('warning');
      }
    }

    // Anti-cheat: Tab visibility
    document.addEventListener('visibilitychange', () => {
      if (document.hidden) {
        isTabActive = false;
        tabSwitchCount++;

        // Log event
        logEvent('tab_switch', { count: tabSwitchCount });

        // Show warning
        const warning = document.getElementById('proctoring-warning');
        warning.classList.add('show');
        setTimeout(() => warning.classList.remove('show'), 3000);
      } else {
        isTabActive = true;
      }
    });

    // Anti-cheat: Copy/paste detection
    function logCopyPaste(event) {
      copyPasteCount++;
      logEvent('copy_paste', { count: copyPasteCount });
    }

    // Log anti-cheat event
    async function logEvent(eventType, eventData) {
      try {
        await fetch('/api/assessments/event', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          },
          body: JSON.stringify({
            sessionId,
            eventType,
            eventData
          })
        });
      } catch (error) {
        console.error('Failed to log event:', error);
      }
    }

    // Prevent right-click (basic anti-cheat)
    document.addEventListener('contextmenu', e => e.preventDefault());

    // Initialize on load
    document.addEventListener('DOMContentLoaded', initAssessment);
  </script>
</body>
</html>
