      const answersGiven = JSON.parse(result.answers_given || '[]');
      const correctCount = answersGiven.filter(a => a.isCorrect).length;

      document.getElementById('stat-correct').textContent = `${correctCount}/10`;
      document.getElementById('stat-difficulty').textContent = `${result.max_difficulty_reached || 2}/5`;

      const duration = result.duration_seconds || 0;
      const minutes = Math.floor(duration / 60);
      const seconds = Math.floor(duration % 60);
      document.getElementById('stat-time').textContent = `${minutes}m ${seconds}s`;

