  if (new Date(storedToken.expires_at) < new Date()) {
    return { error: 'Refresh token expired' };
  }

  // Revoke old token
  await pool.query(
    'UPDATE refresh_tokens SET is_revoked = true, last_used_at = NOW() WHERE id = $1',
    [storedToken.id]
  );

